/// <summary>
/// The ETGSOWorkflowApprovalNewEventHandler workflow outcome event handler.
/// </summary>
public final class ETGSOWorkflowApprovalNewEventHandler implements WorkflowElementCanceledEventHandler,
	WorkflowElemChangeRequestedEventHandler,
	WorkflowElementCompletedEventHandler,
	WorkflowElementReturnedEventHandler,
	WorkflowElementStartedEventHandler,
	WorkflowElementDeniedEventHandler,
	WorkflowWorkItemsCreatedEventHandler
{

}

Method.Source:
public void changeRequested(WorkflowElementEventArgs _workflowElementEventArgs)
{
    RecId documentRecId = _workflowElementEventArgs.parmWorkflowContext().parmRecId();
    SalesTable::updateWorkflowStatus(documentRecId, VersioningDocumentState::Draft);
}

public void returned(WorkflowElementEventArgs _workflowElementEventArgs)
{
    RecId documentRecId = _workflowElementEventArgs.parmWorkflowContext().parmRecId();
    SalesTable::updateWorkflowStatus(documentRecId, VersioningDocumentState::Rejected);

}
